const raw = $input.first().json;
const body = raw.body || raw;

const projectName = body.projectName || 'Untitled';
const apiKey = body.apiKey || '';
const videoModel = body.videoModel || 'seedance-2.0';
const aspectRatio = body.aspectRatio || '16:9';
const quality = body.quality || 'standard';

const characters = body.characters || {};
const scenes = body.scenes || [];
const referenceVideoUrl = body.referenceVideoUrl || '';
const music = body.music || { enabled: false, description: '', url: '' };

const ttsJobs = [];
for (let si = 0; si < scenes.length; si++) {
  const sc = scenes[si];
  if (sc.dialogues && sc.dialogues.length > 0) {
    for (let di = 0; di < sc.dialogues.length; di++) {
      const d = sc.dialogues[di];
      const charName = d.character || '';
      const char = characters[charName] || {};
      ttsJobs.push({
        sceneIndex: si,
        dialogueIndex: di,
        character: charName,
        text: d.text || '',
        voiceId: char.voiceId || '',
        voiceDescription: char.voiceDescription || '',
        gender: char.gender || 'female',
        age: char.age || 30
      });
    }
  }
}

return [{
  json: {
    projectName,
    apiKey,
    videoModel,
    aspectRatio,
    quality,
    characters,
    scenes,
    referenceVideoUrl,
    music,
    ttsJobs,
    supabaseUrl: 'https://supabase.fantomnatashi.ru'
  }
}];

const data = $input.first().json;
const supabaseUrl = data.supabaseUrl;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const bucket = 'avd-files';

async function uploadToSupabase(fileUrl, destPath) {
  if (!fileUrl || fileUrl.startsWith(supabaseUrl)) return fileUrl;
  try {
    const response = await fetch(fileUrl);
    const buffer = await response.arrayBuffer();
    const uploadUrl = `${supabaseUrl}/storage/v1/object/${bucket}/${destPath}`;
    const uploadResp = await fetch(uploadUrl, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${serviceKey}`,
        'apikey': serviceKey,
        'Content-Type': 'application/octet-stream',
        'x-upsert': 'true'
      },
      body: Buffer.from(buffer)
    });
    if (uploadResp.ok) {
      return `${supabaseUrl}/storage/v1/object/public/${bucket}/${destPath}`;
    }
  } catch(e) {}
  return fileUrl;
}

const timestamp = Date.now();
const chars = data.characters || {};

for (const [name, char] of Object.entries(chars)) {
  const safeName = name.replace(/[^a-zA-Z0-9\u0400-\u04FF]/g, '_');
  if (char.facePhotoUrl) {
    char.facePhotoUrl = await uploadToSupabase(char.facePhotoUrl, `${timestamp}/${safeName}_face.jpg`);
  }
  if (char.referenceVideoUrl) {
    char.referenceVideoUrl = await uploadToSupabase(char.referenceVideoUrl, `${timestamp}/${safeName}_ref.mp4`);
  }
}

if (data.referenceVideoUrl) {
  data.referenceVideoUrl = await uploadToSupabase(data.referenceVideoUrl, `${timestamp}/reference_video.mp4`);
}

data.characters = chars;
data._timestamp = timestamp;

return [{ json: data }];

const data = $input.first().json;
const jobs = data.ttsJobs || [];

if (jobs.length === 0) {
  return [{ json: { ...data, _noTTS: true, audioFiles: [] } }];
}

return jobs.map(job => ({
  json: {
    ...job,
    _parentData: data
  }
}));

const items = $input.all();
const results = [];

for (const item of items) {
  const audioUrl = item.json?.data?.audio?.audio_url || item.json?.audio_url || item.json?.data?.audio_url || '';
  results.push({
    json: {
      sceneIndex: item.json.sceneIndex ?? 0,
      dialogueIndex: item.json.dialogueIndex ?? 0,
      character: item.json.character || '',
      audioUrl: audioUrl,
      text: item.json.text || ''
    }
  });
}

return results;

const audioItems = $input.all();
const uploadData = $('3. Upload Files to Supabase').first().json;

return [{
  json: {
    ...uploadData,
    audioItems: audioItems.map((item, i) => ({
      sceneIndex: item.json?.sceneIndex ?? i,
      dialogueIndex: item.json?.dialogueIndex ?? 0,
      character: item.json?.character || '',
      hasBinary: !!item.binary?.data
    }))
  }
}];

const fs = require('fs');
const data = $input.first().json;
const audioItems = $('7. Download Audio').all();
const ts = data._timestamp || Date.now();
const workDir = `/tmp/avd_${ts}`;

fs.mkdirSync(workDir, { recursive: true });

const savedAudio = [];
for (let i = 0; i < audioItems.length; i++) {
  const item = audioItems[i];
  if (item.binary?.data) {
    const filePath = `${workDir}/audio_s${item.json?.sceneIndex || 0}_d${item.json?.dialogueIndex || i}.mp3`;
    const buf = Buffer.from(item.binary.data.data, 'base64');
    fs.writeFileSync(filePath, buf);
    savedAudio.push({
      path: filePath,
      sceneIndex: item.json?.sceneIndex || 0,
      dialogueIndex: item.json?.dialogueIndex || i
    });
  }
}

return [{
  json: {
    ...data,
    workDir,
    savedAudio
  }
}];

const data = $input.first().json;
const scenes = data.scenes || [];
const characters = data.characters || {};

const results = [];
for (let i = 0; i < scenes.length; i++) {
  const sc = scenes[i];
  const charName = sc.characters?.[0] || Object.keys(characters)[0] || '';
  const char = characters[charName] || {};

  results.push({
    json: {
      sceneIndex: i,
      prompt: sc.prompt || sc.description || '',
      duration: sc.duration || 10,
      aspect_ratio: data.aspectRatio || '16:9',
      model: data.videoModel || 'seedance-2.0',
      mode: data.quality === 'high' ? 'pro' : 'std',
      image_url: char.facePhotoUrl || '',
      video_url: (i === 0 && data.referenceVideoUrl) ? data.referenceVideoUrl : '',
      camera_angle: sc.cameraAngle || 'medium shot',
      lighting: sc.lighting || 'natural',
      _workDir: data.workDir,
      _timestamp: data._timestamp,
      _apiKey: data.apiKey
    }
  });
}

return results;

const fs = require('fs');
const videoItems = $input.all();
const parsing = $('2. Parse FormData').first().json;
const audioData = $('9. Save Audio to Disk').first().json;
const workDir = audioData.workDir || `/tmp/avd_${Date.now()}`;
const savedAudio = audioData.savedAudio || [];

fs.mkdirSync(workDir, { recursive: true });

const videoFiles = [];
for (let i = 0; i < videoItems.length; i++) {
  const item = videoItems[i];
  if (item.binary?.data) {
    const filePath = `${workDir}/scene_${i}.mp4`;
    const buf = Buffer.from(item.binary.data.data, 'base64');
    fs.writeFileSync(filePath, buf);
    videoFiles.push(filePath);
  }
}

const refUrl = parsing.referenceVideoUrl || '';
const cmds = [];

if (refUrl) {
  cmds.push(`curl -sL "${refUrl}" -o ${workDir}/ref.mp4`);
}

let concatContent = '';
if (refUrl) concatContent += `file '${workDir}/ref.mp4'\n`;
videoFiles.forEach(f => { concatContent += `file '${f}'\n`; });
fs.writeFileSync(`${workDir}/concat_video.txt`, concatContent);

cmds.push(`ffmpeg -y -f concat -safe 0 -i ${workDir}/concat_video.txt -c:v libx264 -preset fast -crf 23 ${workDir}/merged_video.mp4`);

if (savedAudio.length > 0) {
  const sceneAudioMap = {};
  savedAudio.forEach(a => {
    if (!sceneAudioMap[a.sceneIndex]) sceneAudioMap[a.sceneIndex] = [];
    sceneAudioMap[a.sceneIndex].push(a.path);
  });

  const allAudioPaths = [];
  const sceneIndices = Object.keys(sceneAudioMap).sort((a,b) => a - b);

  if (refUrl) {
    cmds.push(`ffprobe -v error -show_entries format=duration -of csv=p=0 ${workDir}/ref.mp4 > ${workDir}/ref_duration.txt`);
    cmds.push(`REF_DUR=$(cat ${workDir}/ref_duration.txt) && ffmpeg -y -f lavfi -i anullsrc=r=32000:cl=mono -t $REF_DUR ${workDir}/silence_ref.mp3`);
    allAudioPaths.push(`${workDir}/silence_ref.mp3`);
  }

  for (const si of sceneIndices) {
    const files = sceneAudioMap[si];
    if (files.length === 1) {
      allAudioPaths.push(files[0]);
    } else {
      const sceneConcat = files.map(f => `file '${f}'`).join('\n');
      fs.writeFileSync(`${workDir}/audio_scene_${si}.txt`, sceneConcat);
      cmds.push(`ffmpeg -y -f concat -safe 0 -i ${workDir}/audio_scene_${si}.txt -c copy ${workDir}/audio_scene_${si}.mp3`);
      allAudioPaths.push(`${workDir}/audio_scene_${si}.mp3`);
    }
  }

  const audioConcat = allAudioPaths.map(f => `file '${f}'`).join('\n');
  fs.writeFileSync(`${workDir}/concat_audio.txt`, audioConcat);
  cmds.push(`ffmpeg -y -f concat -safe 0 -i ${workDir}/concat_audio.txt -c copy ${workDir}/merged_audio.mp3`);
  cmds.push(`ffmpeg -y -i ${workDir}/merged_video.mp4 -i ${workDir}/merged_audio.mp3 -c:v copy -c:a aac -map 0:v:0 -map 1:a:0 -shortest ${workDir}/final.mp4`);
} else {
  cmds.push(`cp ${workDir}/merged_video.mp4 ${workDir}/final.mp4`);
}

const music = parsing.music || {};
if (music.enabled && music.url) {
  cmds.push(`curl -sL "${music.url}" -o ${workDir}/music.mp3`);
  cmds.push(`mv ${workDir}/final.mp4 ${workDir}/final_nomusic.mp4`);
  cmds.push(`ffmpeg -y -i ${workDir}/final_nomusic.mp4 -i ${workDir}/music.mp3 -filter_complex "[1:a]volume=0.15[bg];[0:a][bg]amix=inputs=2:duration=first[aout]" -map 0:v -map "[aout]" -c:v copy -c:a aac ${workDir}/final.mp4`);
}

const fullCmd = cmds.join(' && ');

return [{ json: { command: fullCmd, workDir, outputFile: `${workDir}/final.mp4` } }];

const fs = require('fs');
const workDir = $('17. FFmpeg Build Command').first().json.workDir;
const outputFile = $('17. FFmpeg Build Command').first().json.outputFile;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const supabaseUrl = 'https://supabase.fantomnatashi.ru';
const bucket = 'avd-files';
const fileName = `final_${Date.now()}.mp4`;

const fileBuffer = fs.readFileSync(outputFile);

const uploadUrl = `${supabaseUrl}/storage/v1/object/${bucket}/${fileName}`;
const resp = await fetch(uploadUrl, {
  method: 'POST',
  headers: {
    'Authorization': `Bearer ${serviceKey}`,
    'apikey': serviceKey,
    'Content-Type': 'video/mp4',
    'x-upsert': 'true'
  },
  body: fileBuffer
});

const result = await resp.json();
const publicUrl = `${supabaseUrl}/storage/v1/object/public/${bucket}/${fileName}`;

try { fs.rmSync(workDir, { recursive: true, force: true }); } catch(e) {}

return [{
  json: {
    success: resp.ok,
    videoUrl: publicUrl,
    uploadResult: result,
    fileName
  }
}];
